@namespace sv_b62dac11d73a4363aba84f8f5ff0e72a.Components.Catalog

<div class="p-3 border rounded bg-light">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-bold">Categories</label>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input"
                       type="checkbox"
                       id="@($"cat-{category}")"
                       checked="@_selectedCategories.Contains(category)"
                       @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number"
                   class="form-control form-control-sm"
                   placeholder="Min"
                   value="@_minPrice"
                   @onchange="e => _minPrice = ParseDecimal(e.Value)" />
            <span>–</span>
            <input type="number"
                   class="form-control form-control-sm"
                   placeholder="Max"
                   value="@_maxPrice"
                   @onchange="e => _maxPrice = ParseDecimal(e.Value)" />
        </div>
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input"
               type="checkbox"
               id="inStockOnly"
               checked="@_inStockOnly"
               @onchange="e => _inStockOnly = (bool)e.Value!" />
        <label class="form-check-label fw-bold" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@namespace sv_b62dac11d73a4363aba84f8f5ff0e72a.Components.Catalog

<div class="d-flex justify-content-between align-items-center flex-wrap gap-2 mb-3">
    <div class="d-flex align-items-center gap-2">
        <label class="form-label mb-0 fw-bold" for="sortSelect">Sort by:</label>
        <select id="sortSelect"
                class="form-select form-select-sm"
                style="width: auto;"
                value="@SortBy"
                @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    @if (Result is not null)
    {
        var start = (Result.Page - 1) * Result.PageSize + 1;
        var end = Math.Min(Result.Page * Result.PageSize, Result.TotalCount);
        <span class="text-muted">Showing @start–@end of @Result.TotalCount products</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public PagedResult<Product>? Result { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_b62dac11d73a4363aba84f8f5ff0e72a.Components.Catalog

@if (TotalPages > 1)
{
    <nav aria-label="Product catalog pagination">
        <ul class="pagination justify-content-center mt-4">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage - 1)" disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>

            @for (int i = 1; i <= TotalPages; i++)
            {
                var page = i;
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(page)">@page</button>
                </li>
            }

            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage + 1)" disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; } = 1;

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@using sv_b62dac11d73a4363aba84f8f5ff0e72a.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-3 mb-3">
            <CatalogSidebar Categories="_categories" OnFilterApplied="HandleFilterApplied" />
        </div>

        <div class="col-lg-9">
            <CatalogToolbar SortBy="@_sortBy" Result="_result" OnSortChanged="HandleSortChanged" />

            @if (_loading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (_result is not null && _result.Items.Count > 0)
            {
                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
            else
            {
                <div class="text-center py-5 text-muted">
                    <h5>No products found</h5>
                    <p>Try adjusting your filters.</p>
                </div>
            }
        </div>
    </div>
}

@code {
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private PagedResult<Product>? _result;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;
    private bool _loading = true;
    private string? _error;
    private int _totalPages;

    /// <summary>
    /// Raised when a product card is clicked, so the parent layout or host can navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialDataAsync();
    }

    private async Task LoadInitialDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _categories = await ProductService.GetCategoriesAsync();
            await SearchAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            StateHasChanged();

            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            _totalPages = (int)Math.Ceiling((double)_result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire up cart service when available
        return Task.CompletedTask;
    }

    private async Task RetryAsync()
    {
        await LoadInitialDataAsync();
    }
}

